pub fn grade_frame_with_adaptive_grader_16(
    grader: &cuda::AdaptiveGrader,
    pixels: &[u16],
    depth: &[f32],
    width: usize,
    height: usize,
    depth_w: usize,
    depth_h: usize,
    blend_t: f32,
) -> Result<Vec<u16>, GpuError> {
    if pixels.len() != width * height * 3 {
        return Err(GpuError::InvalidInput(format!(
            "pixels length {} != width*height*3 {}",
            pixels.len(),
            width * height * 3
        )));
